import akka.actor.{Actor, ActorSystem, Props}

// Message classes
case class Deposit(amount: Double)
case class Withdraw(amount: Double)

class AccountManagerActor() extends Actor {

  var balance: Double = 0

  def receive: Receive = {
    case Deposit(amount) =>
      balance += amount

    case Withdraw(amount) =>
      if (amount <= balance) {
        balance -= amount
      } else {
        sender() ! "Insufficient funds"
      }
  }
}

// Usage
val system = ActorSystem("BankingSystem")
val accountManager = system.actorOf(Props[AccountManagerActor], "accountManager")

accountManager ! Deposit(1000)
accountManager ! Withdraw(300)
system.terminate()